import{_ as i,o as s,c as l,a2 as n}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"线框图、原型保真度与设计规范","description":"","frontmatter":{},"headers":[],"relativePath":"03-interaction-design/notes/foundations/05-wireframe-prototype-fidelity-spec.md","filePath":"03-interaction-design/notes/foundations/05-wireframe-prototype-fidelity-spec.md","lastUpdated":1784248569000}'),t={name:"03-interaction-design/notes/foundations/05-wireframe-prototype-fidelity-spec.md"};function e(r,a,p,d,h,o){return s(),l("div",null,[...a[0]||(a[0]=[n(`<h1 id="线框图、原型保真度与设计规范" tabindex="-1">线框图、原型保真度与设计规范 <a class="header-anchor" href="#线框图、原型保真度与设计规范" aria-label="Permalink to &quot;线框图、原型保真度与设计规范&quot;">​</a></h1><p>线框图用于表达结构，原型用于模拟一部分真实行为，保真度描述模拟在哪些维度接近成品，设计规范用于把决策转化为可实现、可检查的规则。它们服务于不同问题，不能互相替代。</p><h2 id="概念边界" tabindex="-1">概念边界 <a class="header-anchor" href="#概念边界" aria-label="Permalink to &quot;概念边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>产物</th><th>核心用途</th><th>能证明</th><th>不能证明</th></tr></thead><tbody><tr><td>线框图</td><td>表达信息层级、区域、控件与导航关系</td><td>内容优先级和大致结构</td><td>真实交互、性能和最终视觉质量</td></tr><tr><td>低保真原型</td><td>快速模拟概念与主流程</td><td>入口、步骤、顺序是否可理解</td><td>真实输入、滚动、焦点和等待体验</td></tr><tr><td>中保真原型</td><td>用真实文案、数据和关键状态走查任务</td><td>任务路径、内容、分支和反馈</td><td>完整平台行为与后端结果</td></tr><tr><td>高保真原型</td><td>接近最终视觉、动效与局部行为</td><td>视觉层级、过渡和细节理解</td><td>生产性能、兼容性、安全和可访问性合规</td></tr><tr><td>设计规范</td><td>定义结构、状态、行为、内容与实现边界</td><td>团队应实现和验收什么</td><td>实现本身是否正确</td></tr></tbody></table><p>保真度不是单一的“高或低”。一个原型可能视觉保真度高，但数据、内容、交互和技术保真度低。选择原型时应分别说明：</p><ul><li><strong>结构保真度</strong>：布局和信息关系有多接近成品。</li><li><strong>内容保真度</strong>：文案、数据长度和数据分布是否真实。</li><li><strong>交互保真度</strong>：输入、滚动、键盘、焦点、分支和恢复实现到什么程度。</li><li><strong>视觉保真度</strong>：颜色、排版、图标、间距和动效有多完整。</li><li><strong>数据与技术保真度</strong>：是否连接真实接口、延迟、错误和平台能力。</li></ul><h2 id="由问题决定产物" tabindex="-1">由问题决定产物 <a class="header-anchor" href="#由问题决定产物" aria-label="Permalink to &quot;由问题决定产物&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q[&quot;写出待验证问题&quot;] --&gt; D{&quot;问题属于什么层次？&quot;}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt;|分类与层级| W[&quot;线框图或内容模型&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt;|流程与理解| L[&quot;低/中保真原型&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt;|输入、焦点、响应式| C[&quot;可运行代码原型&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt;|视觉与动效| H[&quot;高保真原型&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    W --&gt; T[&quot;执行验证&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L --&gt; T</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; T</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; T</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    T --&gt; S[&quot;沉淀设计规范&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>原则是使用能回答当前问题的最低必要成本，不是固定从低保真顺序升级到高保真。若要验证键盘焦点，纸面原型无法回答；若要验证分类命名，先制作完整视觉稿不会增加有效证据。</p><h2 id="线框图怎样制作" tabindex="-1">线框图怎样制作 <a class="header-anchor" href="#线框图怎样制作" aria-label="Permalink to &quot;线框图怎样制作&quot;">​</a></h2><p>线框图至少应表达：</p><ul><li>页面或容器的目的和主标题；</li><li>主要、次要与辅助内容的顺序；</li><li>导航、输入、列表、详情与操作区域；</li><li>关键入口、出口和页面间关系；</li><li>代表性内容长度、空状态和错误区域；</li><li>对响应式变化的结构假设。</li></ul><p>灰色方块和占位文案不能帮助判断真实内容。即使视觉低保真，也应使用接近真实长度的标题、标签、错误和数据，避免低估换行、密度与信息差异。</p><h2 id="原型范围怎样定义" tabindex="-1">原型范围怎样定义 <a class="header-anchor" href="#原型范围怎样定义" aria-label="Permalink to &quot;原型范围怎样定义&quot;">​</a></h2><p>每个原型开始前写一张范围卡：</p><div class="language-markdown vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 待验证问题：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 目标任务与场景：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 参与入口：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 实现的路径和状态：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 未实现部分：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 假数据与真实数据：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 通过标准：</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 原型结果不得外推到：</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>原型应只模拟验证所需的行为，但不能让体验者误以为未实现行为已经可用。假按钮应删除、禁用并说明，或真实连接到明确的占位结果；不能点击后无响应。</p><h3 id="关键状态" tabindex="-1">关键状态 <a class="header-anchor" href="#关键状态" aria-label="Permalink to &quot;关键状态&quot;">​</a></h3><p>至少根据任务选择：初始、加载、空、成功、失败、无权限、离线、过期、部分成功、取消、重试和并发冲突。静态原型可以为状态建立独立画板；可运行原型应提供测试开关或固定数据，使每个状态可重复触发。</p><h3 id="键盘、焦点与响应式" tabindex="-1">键盘、焦点与响应式 <a class="header-anchor" href="#键盘、焦点与响应式" aria-label="Permalink to &quot;键盘、焦点与响应式&quot;">​</a></h3><p>需要验证以下问题时，应使用浏览器或平台可运行原型：</p><ul><li>自然 Tab 顺序、焦点可见性、对话框焦点约束与关闭后恢复；</li><li>表单标签、错误关联、动态状态消息和辅助技术语义；</li><li>内容重排、缩放、软键盘、滚动和触控目标；</li><li>原生控件、浏览器历史、文件上传和拖放等平台行为。</li></ul><p>设计工具中的热点连线无法证明这些行为。高保真视觉也不能替代语义和输入方式测试。</p><h2 id="设计规范应包含什么" tabindex="-1">设计规范应包含什么 <a class="header-anchor" href="#设计规范应包含什么" aria-label="Permalink to &quot;设计规范应包含什么&quot;">​</a></h2><h3 id="组件规范" tabindex="-1">组件规范 <a class="header-anchor" href="#组件规范" aria-label="Permalink to &quot;组件规范&quot;">​</a></h3><ul><li>组件用途、适用条件与禁止场景；</li><li>结构、可访问名称、语义和内容要求；</li><li>默认、悬停、焦点、按下、选中、禁用、只读、加载和错误状态；</li><li>鼠标、触控、键盘与辅助技术行为；</li><li>内容长度、图标、国际化和无障碍约束。</li></ul><h3 id="流程规范" tabindex="-1">流程规范 <a class="header-anchor" href="#流程规范" aria-label="Permalink to &quot;流程规范&quot;">​</a></h3><ul><li>入口、前置条件、主路径、分支和完成标准；</li><li>每一步的用户动作、系统响应、数据状态和反馈；</li><li>失败、取消、中断、重试、过期和并发处理；</li><li>URL、浏览器历史、草稿和刷新恢复。</li></ul><h3 id="响应式规范" tabindex="-1">响应式规范 <a class="header-anchor" href="#响应式规范" aria-label="Permalink to &quot;响应式规范&quot;">​</a></h3><p>不要只交付三个固定宽度截图。应说明内容在什么条件下换行、堆叠、隐藏、滚动或改变容器，以及信息优先级是否保持。断点是实现条件，不是设备名称的替代品。</p><h3 id="可验收表达" tabindex="-1">可验收表达 <a class="header-anchor" href="#可验收表达" aria-label="Permalink to &quot;可验收表达&quot;">​</a></h3><p>“按钮置灰”只描述外观；“请求进行时阻止重复提交，按钮保留可读名称并显示忙碌状态；请求失败后恢复可操作，输入保持不变”才是可实现和可测试的规则。</p><h2 id="完整案例-邀请项目成员" tabindex="-1">完整案例：邀请项目成员 <a class="header-anchor" href="#完整案例-邀请项目成员" aria-label="Permalink to &quot;完整案例：邀请项目成员&quot;">​</a></h2><h3 id="待验证问题" tabindex="-1">待验证问题 <a class="header-anchor" href="#待验证问题" aria-label="Permalink to &quot;待验证问题&quot;">​</a></h3><p>用户能否理解邀请结果中“已邀请”“已是成员”“地址无效”三类状态，并修正失败项？</p><h3 id="原型策略" tabindex="-1">原型策略 <a class="header-anchor" href="#原型策略" aria-label="Permalink to &quot;原型策略&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>选择</th><th>理由</th></tr></thead><tbody><tr><td>结构</td><td>中保真</td><td>需要真实结果分组和错误摘要</td></tr><tr><td>内容</td><td>高保真</td><td>邮箱长度、重复项和错误文案直接影响理解</td></tr><tr><td>交互</td><td>可运行</td><td>需要验证键盘、粘贴多个地址、焦点和部分成功</td></tr><tr><td>视觉</td><td>中保真</td><td>品牌细节不影响当前问题</td></tr><tr><td>数据</td><td>固定测试集</td><td>必须重复制造三类结果</td></tr></tbody></table><h3 id="原型状态" tabindex="-1">原型状态 <a class="header-anchor" href="#原型状态" aria-label="Permalink to &quot;原型状态&quot;">​</a></h3><ol><li>初始：空输入，提交不可用，但原因无需只靠禁用表达。</li><li>输入：支持逐个输入或粘贴多个地址，明确分隔规则。</li><li>本地错误：格式错误关联到具体项，可键盘定位和删除。</li><li>提交中：防止重复提交，保留输入上下文。</li><li>部分成功：分别列出成功、已存在和失败；只允许重试失败项。</li><li>完全失败：保留全部输入，说明是否有任何邀请已发出。</li><li>完成：用户可返回成员列表，列表显示最新成员或待接受状态。</li></ol><h3 id="规范摘录" tabindex="-1">规范摘录 <a class="header-anchor" href="#规范摘录" aria-label="Permalink to &quot;规范摘录&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>当结果为部分成功时：</span></span>
<span class="line"><span>- 标题显示“3 个邀请已发送，2 个需要处理”；</span></span>
<span class="line"><span>- 成功项不再进入重试请求；</span></span>
<span class="line"><span>- 失败项保留输入与服务端原因；</span></span>
<span class="line"><span>- 焦点移动到结果标题；</span></span>
<span class="line"><span>- 修正后提交只发送失败项；</span></span>
<span class="line"><span>- 返回成员列表后，通过状态消息宣布成员列表已更新。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="可执行工作步骤" tabindex="-1">可执行工作步骤 <a class="header-anchor" href="#可执行工作步骤" aria-label="Permalink to &quot;可执行工作步骤&quot;">​</a></h2><ol><li>把“想看看方案”改写为可以判断对错的验证问题。</li><li>确定参与者、任务、场景、路径和通过标准。</li><li>分别选择结构、内容、交互、视觉和数据保真度。</li><li>制作最小原型，加入真实文案、代表性数据和必要状态。</li><li>显式标注未实现内容和原型限制。</li><li>执行任务走查或测试，记录观察事实而非只收集偏好。</li><li>把被证实的决策写成状态、行为与验收规范。</li><li>在真实实现中重新验证原型无法证明的性能、兼容性和无障碍行为。</li></ol><h2 id="常见错误与边界" tabindex="-1">常见错误与边界 <a class="header-anchor" href="#常见错误与边界" aria-label="Permalink to &quot;常见错误与边界&quot;">​</a></h2><ul><li>把静态页面连线称为完整交互原型，却没有输入、状态或失败。</li><li>用“低保真”作为使用无意义占位文案的理由。</li><li>只设计成功路径，测试者无法重复制造错误。</li><li>高保真动效造成已经完成开发的错觉。</li><li>用原型顺滑程度推断真实接口性能。</li><li>只标像素与颜色，不写语义、状态、键盘和数据条件。</li><li>原型测试发现问题后只修改画面，没有更新规范与假设记录。</li></ul><h2 id="验证步骤" tabindex="-1">验证步骤 <a class="header-anchor" href="#验证步骤" aria-label="Permalink to &quot;验证步骤&quot;">​</a></h2><ol><li>让未参与制作的人依据范围卡说明原型能与不能验证什么。</li><li>用预设数据逐一触发主路径、空、失败、部分成功和取消。</li><li>仅用键盘完成原型任务，核对焦点顺序、可见性和恢复。</li><li>在 320 CSS 像素、200% 缩放和真实长文案下检查结构。</li><li>对照规范逐条标记“原型可证明”“需代码验证”“需生产数据验证”。</li><li>实现后重复关键任务，确认规范没有因技术差异失效。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>为“批量上传图片并处理失败项”设计一套原型计划和规范。</p><p>完成时应满足：</p><ul><li>写出一个明确验证问题与可观察通过标准；</li><li>分别说明五种保真度维度，而不是只写“中保真”；</li><li>覆盖选择、上传、进度、取消、部分成功、失败和重试；</li><li>使用真实文件名、大小、错误和长内容；</li><li>写出键盘、焦点、状态消息和响应式规则；</li><li>标明原型不能证明的后端、性能与兼容性问题；</li><li>规范足以让开发者实现，让测试者逐条验收。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://www.gov.uk/service-manual/design/making-prototypes" target="_blank" rel="noreferrer">GOV.UK Service Manual：Making prototypes</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/tutorials/forms/" target="_blank" rel="noreferrer">W3C WAI：Forms Tutorial</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/ARIA/apg/about/introduction/" target="_blank" rel="noreferrer">W3C WAI-ARIA APG：Introduction</a>（访问日期：2026-07-17）</li><li><a href="https://www.w3.org/WAI/test-evaluate/" target="_blank" rel="noreferrer">W3C WAI：Evaluating Web Accessibility Overview</a>（访问日期：2026-07-17）</li></ul>`,53)])])}const b=i(t,[["render",e]]);export{u as __pageData,b as default};
